  s += `<rect x="176.6" y="169" width="10.3" height="1.9" rx="0.8" fill="#6A755A" stroke="${OUT}" stroke-width="0.7"/>`;
  s += `<circle cx="180" cy="181.4" r="0.9" fill="#2E2921"/><circle cx="184" cy="181.4" r="0.9" fill="#2E2921"/>`;

  // near sidewalk with joints, crack, stain
