    win += `<rect x="${w*(0.08+i*0.17)}" y="${h*0.18}" width="${w*0.12}" height="${h*0.30}" rx="0.8" fill="#7A8FA0" stroke="${OUT}" stroke-width="${h*0.02}"/>`;
